mapper.select:
SELECT CO_ID, BAT_JB_ID, BAT_JB_NM, BAT_JB_CLSS, BAT_JB_STS_CD, BAT_JB_DESC, CRON_XPR_VAL, CRON_DESC, BAT_JB_NXT_RUN_DT, BAT_JB_LST_RUN_DT, USE_FLG, BAT_JB_PARA, CRE_USR_ID, CRE_DT, UPD_USR_ID, UPD_DT FROM COM_BAT_CFG WHERE CO_ID = #{coId}
AND BAT_JB_ID = #{batJbId}
AND BAT_JB_NM ILIKE '%' || #{batJbNm} || '%'
AND USE_FLG = #{useFlg}
ORDER BY ${sort.sortField} ${sort.sortType}, UPD_DT DESC
ORDER BY UPD_DT DESC

SELECT CO_ID, BAT_JB_ID, BAT_JB_NM, BAT_JB_CLSS, BAT_JB_STS_CD, BAT_JB_DESC, CRON_XPR_VAL, CRON_DESC, BAT_JB_NXT_RUN_DT, BAT_JB_LST_RUN_DT, USE_FLG, BAT_JB_PARA, CRE_USR_ID, CRE_DT, UPD_USR_ID, UPD_DT FROM COM_BAT_CFG WHERE CO_ID = #{coId}
AND BAT_JB_ID = #{batJbId}
AND BAT_JB_NM ILIKE '%' || #{batJbNm} || '%'
AND USE_FLG = #{useFlg}
LIMIT 1

SELECT CO_ID, BAT_JB_ID, BAT_JB_NM, BAT_JB_CLSS, BAT_JB_STS_CD, BAT_JB_DESC, CRON_XPR_VAL, CRON_DESC, BAT_JB_NXT_RUN_DT, BAT_JB_LST_RUN_DT, USE_FLG, BAT_JB_PARA, CRE_USR_ID, CRE_DT, UPD_USR_ID, UPD_DT FROM COM_BAT_CFG WHERE CO_ID = #{coId}
AND BAT_JB_ID = #{batJbId}
AND BAT_JB_NM ILIKE '%' || #{batJbNm} || '%'
AND USE_FLG = #{useFlg}
LIMIT 1

mapper.delete:
DELETE FROM COM_BAT_CFG
WHERE CO_ID = #{coId}
AND BAT_JB_ID = #{batJbId}

mapper.select:
SELECT CO_ID, BAT_EXEC_ID, BAT_JB_ID, BAT_JB_STS_CD, BAT_JB_ST_DT, BAT_JB_END_DT, BAT_JB_PARA, BAT_JB_MSG, CRE_USR_ID, CRE_DT, UPD_USR_ID, UPD_DT FROM COM_BAT_HIS WHERE CO_ID = #{coId} AND BAT_JB_ID = #{batJbId}
ORDER BY ${sort.sortField} ${sort.sortType}, UPD_DT DESC
ORDER BY UPD_DT DESC
LIMIT #{pagination.pageSize} OFFSET (#{pagination.current} - 1) * #{pagination.pageSize}

SELECT COUNT(*)
	FROM COM_BAT_HIS
    WHERE CO_ID = #{coId}
   	AND BAT_JB_ID = #{batJbId}
